queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?standupcomedians a :standupcomedians .
    ?standupcomedians p:name ?name .
    ?standupcomedians p:duration_of_performance ?duration_of_performance_f .
    FILTER((STR(?duration_of_performance_f) = "60" || STR(?duration_of_performance_f) = "60.0"))
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?magicians a :Magicians .
    ?magicians p:name ?name .
    ?magicians p:duration_of_performance ?duration_of_performance_f .
    FILTER((STR(?duration_of_performance_f) = "60" || STR(?duration_of_performance_f) = "60.0"))
    BIND(?name AS ?o0)
  }
}

